def counting_sort(exp):
    n = len(vetor)
    saida = [0] * n
    baldes = [0] * 10

    for i in range(n):
        indice = vetor[i] // exp
        baldes[indice % 10] += 1

    for i in range(1, 10):
        baldes[i] += baldes[i - 1]

    i = n - 1
    while i >= 0:
        indice = vetor[i] // exp
        saida[baldes[indice % 10] - 1] = vetor[i]
        baldes[indice % 10] -= 1
        i -= 1

    for i in range(n):
        vetor[i] = saida[i]

def radix_sort():
    maior = max(vetor)

    exp = 1
    while maior // exp > 0:
        counting_sort(exp)
        exp *= 10

if __name__ == "__main__":
    radix_sort()